```typescript
const PROCESSING_FEE = 5;
const BASE_PREMIUMS = { sword: 100, amulet: 60 };
const FIRST_INSURANCE_RATE = 0.1;

export const quote = (_customer, items, _contractNumber) => {
  const basePremiumTotal = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const cursedSurcharge = items.reduce((sum, item) => {
    return item.cursed ? sum + BASE_PREMIUMS[item.type] * 0.5 : sum;
  }, 0);
  const firstInsuranceSurcharge = basePremiumTotal * FIRST_INSURANCE_RATE;
  return Math.ceil(basePremiumTotal + cursedSurcharge + firstInsuranceSurcharge) + PROCESSING_FEE;
};
